{% set doc = doc or {} %}
<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Annexe à la Décision de Mouvement de Crédits</title>
    <style>
        /* Force A4 landscape (paysage) */
        @page {
            size: A4 landscape;
            margin: 20mm;
        }
        body {
            font-family: "Times New Roman", serif;
            font-size: 12pt;
            line-height: 1.4;
        }
        .header {
            text-align: center;
            font-weight: bold;
            margin-bottom: 20px;
        }
        .section-title {
            font-weight: bold;
            margin-top: 20px;
            margin-bottom: 10px;
            text-decoration: underline;
        }
        table {
            width: 100%;
            border-collapse: collapse;
            margin-bottom: 20px;
        }
        th, td {
            border: 1px solid #000;
            padding: 6px 10px;
            text-align: center;
        }
        .signature {
            margin-top: 40px;
            text-align: right;
            font-weight: bold;
        }
    </style>
</head>
<body>

    <div class="header">
        REPUBLIQUE ALGERIENNE DEMOCRATIQUE ET POPULAIRE <br>
        MINISTERE DE L’ENSEIGNEMENT SUPERIEUR ET DE LA RECHERCHE SCIENTIFIQUE <br>
        UNIVERSITE MAMMERI DE TIZI-OUZOU <br>
        FACULTE DU GENIE ELECTRIQUE ET INFORMATIQUE <br><br>
        <span style="font-size:14pt;">ANNEXE A LA DECISION DE MOUVEMENT DE CREDITS</span>
    </div>

    <div class="section-title">ETAT * A * CREDITS ANNULÉS</div>
    <table>
        <thead>
            <tr>
                <th>Chapitre</th>
                <th>Article</th>
                <th>Intitulé</th>
                <th>Crédits alloués</th>
                <th>Montants de mouvement</th>
                <th>Crédits révisés</th>
            </tr>
        </thead>
        <tbody>
            <tr>
                <td>{{doc.chapitre}}</td>
                <td>{{doc.article_source}}</td>
                <td>{{doc.intitule_article_source}}</td>
                <td>{{doc.solde_disponible_source}}</td>
                <td>{{doc.montant_transfere}}</td>
                <td>{{doc.solde_disponible_source-doc.montant_transfere}}</td>
            </tr>
            <tr>
                <td colspan="3"><strong>Total</strong></td>
                <td>{{doc.solde_disponible_source}}</td>
                <td>{{doc.montant_transfere}}</td>
                <td>{{doc.solde_disponible_source-doc.montant_transfere}}</td>
            </tr>
        </tbody>
    </table>
{% set m_article = frappe.get_doc("Article", doc.annee) %}
    <div class="section-title">ETAT * B * CREDITS OUVERTS</div>
    <table>
        <thead>
            <tr>
                <th>Chapitre</th>
                <th>Article</th>
                <th>Intitulé</th>
                <th>Crédits alloués</th>
                <th>Montants de mouvement</th>
                <th>Crédits révisés</th>
            </tr>
        </thead>
        <tbody>
            <tr>
                <td>{{doc.chapitre}}</td>
                <td>{{doc.article_destination}}</td>
                <td>{{doc.intitule_article_destination}}</td>
                <td>{{doc.solde_disponible_source}}</td>
                <td>{{doc.montant_transfere}}</td>
                <td>{{doc.solde_disponible_source+doc.montant_transfere}}</td>
            </tr>
            <tr>
                <td colspan="3"><strong>Total</strong></td>
                <td>{{doc.solde_disponible_source}}</td>
                <td>{{doc.montant_transfere}}</td>
                <td>{{doc.solde_disponible_source+doc.montant_transfere}}</td>
            </tr>
        </tbody>
    </table>

    <div class="signature">
        L’ORDONNATEUR <br>
        (Signature et cachet)
    </div>

</body>
</html>
